:root {
	/* Typography */
	--font-family: 'Inter', 'Open Sans', sans-serif;
	--font-weight-normal: 400;
	--font-weight-bold: 600;

	--font-size-body: 13px;
	--font-size-label: 13px;
	--font-size-input: 14px;
	--font-size-header: 22px;
	--font-size-paragraph: 14px;
	--font-size-link: 12px;
	--font-size-error: 12px;

	--font-size-html-h1: 30px;
	--font-size-html-h2: 22px;
	--font-size-html-h3: 18px;
	--font-size-html-h4: 15px;
	--font-size-html-h5: 13px;
	--font-size-html-h6: 11px;

	--font-size-subheader: 13px;

	/* =================================
	   Neutral modern palette
	================================= */

	/* Base */
	--color-background: #f3f4f6;
	--color-card-bg: #ffffff;

	/* Borders & shadows */
	--color-card-border: #e5e7eb;
	--color-input-border: #d1d5db;
	--color-card-shadow: rgba(0, 0, 0, 0.05);

	--box-shadow-card: 
		0px 8px 20px rgba(0, 0, 0, 0.04),
		0px 2px 6px rgba(0, 0, 0, 0.03);

	/* Text */
	--color-header: #0f172a;
	--color-header-subtext: #64748b;
	--color-label: #334155;
	--color-input-text: #0f172a;
	--color-html-text: #374151;

	/* Links */
	--color-link: #475569;
	--color-html-link: #1e293b;

	/* Focus (más moderno) */
	--color-focus-border: #4f46e5;

	/* Buttons */
	--color-submit-btn-bg: #0f172a;
	--color-submit-btn-text: #ffffff;

	/* Secondary */
	--color-clear-button-bg: #9ca3af;

	/* Notices */
	--color-test-notice-text: #92400e;
	--color-test-notice-bg: #fffbeb;
	--color-test-notice-border: #fde68a;

	/* Error */
	--color-error: #dc2626;

	/* Required */
	--color-required: #0f172a;

	/* Border Radii */
	--border-radius-card: 12px;
	--border-radius-input: 10px;
	--border-radius-clear-btn: 50%;
	--card-border-radius: 12px;

	/* Spacing */
	--padding-container-top: 28px;
	--padding-card: 28px;
	--padding-test-notice-vertical: 12px;
	--padding-test-notice-horizontal: 24px;
	--margin-bottom-card: 18px;
	--padding-form-input: 12px;

	--card-padding: 28px;
	--card-margin-bottom: 18px;

	/* Dimensions */
	--container-width: 460px;
	--submit-btn-height: 50px;
	--checkbox-size: 18px;

	/* Others */
	--opacity-placeholder: 0.5;
}


/* =========================
   Inputs
========================= */

input, textarea, select {
	border: 1px solid var(--color-input-border);
	border-radius: var(--border-radius-input);
	padding: var(--padding-form-input);
	font-size: var(--font-size-input);
	color: var(--color-input-text);
	background: #fff;
	transition: all 0.2s ease;
}

input:focus, textarea:focus, select:focus {
	outline: none;
	border-color: var(--color-focus-border);
	box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.12);
}


/* =========================
   Buttons
========================= */

button {
	height: var(--submit-btn-height);
	background: var(--color-submit-btn-bg);
	color: var(--color-submit-btn-text);
	border: none;
	border-radius: var(--border-radius-input);
	font-weight: var(--font-weight-bold);
	font-size: 14px;
	cursor: pointer;
	transition: all 0.2s ease;
}

button:hover {
	transform: translateY(-1px);
	opacity: 0.95;
}

button:active {
	transform: scale(0.98);
}


/* =========================
   Card
========================= */

.form-card {
	background: var(--color-card-bg);
	border: 1px solid var(--color-card-border);
	border-radius: var(--card-border-radius);
	box-shadow: var(--box-shadow-card);
	padding: var(--card-padding);
}


/* =========================
   Labels
========================= */

label {
	font-size: var(--font-size-label);
	color: var(--color-label);
	margin-bottom: 6px;
	display: block;
}


/* =========================
   Text helper
========================= */

small {
	font-size: 12px;
	color: var(--color-header-subtext);
}

