parameters.jsCode:
const datos = $input.first().json;

const hoy = new Date();
const fechaInicio = new Date(datos.startDate);
const fechaFin = new Date(datos.endDate);

// calcular fecha minima permitida (hoy + 7 dias)
const fechaMinima = new Date();
fechaMinima.setDate(hoy.getDate() + 7);

let errores = [];

// validar inicio minimo 7 dias
if (fechaInicio < fechaMinima) {
  errores.push("La solicitud debe hacerse con al menos 7 dias de antelacion");
}

// evitar fechas en fin de semana (opcional pero pro)
const diaInicio = fechaInicio.getDay();
const diaFin = fechaFin.getDay();

if (diaInicio === 0 || diaInicio === 6 || diaFin === 0 || diaFin === 6) {
  errores.push("Las fechas no pueden comenzar o terminar en fin de semana");
}

// validar rango fechas
if (fechaFin <= fechaInicio) {
  errores.push("La fecha de fin debe ser mayor que la fecha de inicio");
}

return [{
  json: {
    ...datos,
    valido: errores.length === 0,
    errores: errores
  }
}];

