const datosFormulario = $node["validar_fechas_solicitud"].json;
const tipo = datosFormulario.requestType;

let diasPermitidos;

if (tipo === "Vacaciones") {
  diasPermitidos = $input.first().json.vacation_days;
} else {
  diasPermitidos = $input.first().json.sick_days;
}

let errores = datosFormulario.errores || [];

// validar dias disponibles
if (datosFormulario.daysRequested > diasPermitidos) {
  errores.push(`Solo tienes ${diasPermitidos} dias disponibles para ${tipo.toLowerCase()}`);
}

return [{
  json: {
    ...datosFormulario,
    vacation_days: diasPermitidos,
    valido: errores.length === 0,
    errores
  }
}];

